 47→
 48→  useLayoutEffect(() => {
 49→    if (isFocused) {
 50→      setHasAttemptedRescue(false);
 51→      rescueClear();
 52→    }
 53→  }, [
 54→    isFocused,
 55→    rescueClear,
 56→  ]);
 57→
 58→  useFocusEffect(
 59→    React.useCallback(() => {
 60→      setHasAttemptedRescue(false);
 61→      rescueClear();
 62→      return undefined;
