56→    isLoadingBalance: pointsBalance.status === PointsBalanceStatus.LOADING,
57→    isErrorBalance: pointsBalance.status === PointsBalanceStatus.ERROR,
58→    products: pointsProducts.products,
59→    isLoadingProducts: pointsProducts.status === PointsProductsStatus.LOADING,
60→    isErrorProducts: pointsProducts.status === PointsProductsStatus.ERROR,
61→    pointsQuantity: parameterPointsProgram.pointsQuantity,
62→    conversionFactor: parameterPointsProgram.conversionFactor,
63→    isLoadingParameterization:
64→      parameterPointsProgram.status === ParameterPointsProgramStatus.LOADING,
65→    isErrorParameterization:
66→      parameterPointsProgram.status === ParameterPointsProgramStatus.ERROR,
67→    requestPointsBalance,
68→    requestPointsProducts,
69→    requestParameterization,
70→    requestInitialData,
71→    clear,
72→    clearBalance,
73→  };
74→}
