23→export function findInvoiceProduct(
24→  products: PointsProduct[],
25→): PointsProduct | undefined {
26→  return products.find(
27→    product =>
28→      product.name?.toLowerCase().includes('fatura') ||
29→      product.action?.toLowerCase().includes('fatura'),
30→  );
