 19→
 20→  useEffect(() => {
 21→    checkHasRedeemed().catch(() => {});
 22→  }, [checkHasRedeemed]);
 23→
 24→  const onPressKeyName = useMemo(
 25→    () => ({
 26→      [normalizeName(KEY_NAME_TO_ICON.MARKETPLACE)]: () => {
 27→        navigation.navigate('RewardProgramMarketplace');
 28→      },
 29→      [normalizeName(KEY_NAME_TO_ICON.FUEL_VOUCHER)]: () => {},
 30→      [normalizeName(KEY_NAME_TO_ICON.MONTHLY_DISCOUNT)]: () => {},
 31→      [normalizeName(KEY_NAME_TO_ICON.CAR_INSURANCE_DISCOUNT)]: () => {},
 32→      [normalizeName(KEY_NAME_TO_ICON.PARKING_DISCOUNT)]: () => {},
 33→      [normalizeName(KEY_NAME_TO_ICON.FINES_DISCOUNT)]: () => {},
 34→      [normalizeName(KEY_NAME_TO_ICON.IPVA_DISCOUNT)]: () => {},
 35→      [normalizeName(KEY_NAME_TO_ICON.AIRLINE_MILES)]: () => {
 36→        navigation.navigate('AirlineMilesMarketplace');
 37→      },
 38→    }),
 39→    [navigation],
 40→  );
 41→
 42→  const handleOnPress = useCallback(
 43→    (keyName: string) => {
 44→      return () => {
 45→        if (keyName in onPressKeyName) {
 46→          onPressKeyName[keyName]();
 47→          const contentIdName = getNormalizedKeyName(keyName)
 48→            .split(' ')
 49→            .join('_')
 50→            .toLowerCase();
 51→
 52→          eventSelectContent({
 53→            content_type: 'cta',
 54→            content_id: `onde_usar_${contentIdName}`,
 55→            location_1: 'monetizacao',
 56→            location_2: 'hub_recompensas_spmais',
 57→            location_3: 'home_hub_recompensas',
 58→          });
 59→        }
 60→      };
 61→    },
 62→    [onPressKeyName],
 63→  );
 64→
 65→  const buildPointsCardItems = useCallback(
 66→    (pointsOptions: PointsProduct[] | undefined): PointsCardItem[] => {
 67→      const rawProducts = extractRawProducts(pointsOptions);
 68→      const builder = PointsCardItemBuilder.getInstance();
 69→
 70→      return rawProducts.filter(isValidProduct).map((product, index) => {
 71→        const normalizedName = normalizeName(product.name);
 72→        const icon = NAME_TO_ICON[normalizedName] || 'icon-default';
 73→
 74→        const isCashbackInInvoice =
 75→          normalizedName === normalizeName(KEY_NAME_TO_ICON.RESCUE_IN_INVOICE);
 76→        const onPress = isCashbackInInvoice
 77→          ? async () => {
 78→              eventSelectContent({
 79→                content_type: 'cta',
 80→                content_id: `onde_usar_cashback_na_fatura`,
 81→                location_1: 'monetizacao',
 82→                location_2: 'hub_recompensas_spmais',
 83→                location_3: 'home_hub_recompensas',
 84→              });
 85→              const rawCF =
 86→                (product as any).conversionFactor ??
 87→                (product as any).convertionFactor ??
 88→                0;
 89→              const conversionFactor = (() => {
 90→                if (typeof rawCF === 'number') return rawCF;
 91→                if (typeof rawCF === 'string') {
 92→                  const n = Number(
 93→                    String(rawCF)
 94→                      .replace(',', '.')
 95→                      .replace(/[^0-9.-]/g, ''),
 96→                  );
 97→                  return Number.isFinite(n) ? n : 0;
 98→                }
 99→                return 0;
100→              })();
101→              const productCode =
102→                (product as any).productCode ?? (product as any).code;
103→              const campaingId =
104→                (product as any).campaingId ??
105→                (product as any).campaignId ??
106→                undefined;
107→
108→              const hasRedeemed = await checkHasRedeemed();
109→              if (hasRedeemed) {
110→                navigation.navigate('InvoiceCashbackPoints', {
111→                  conversionFactor,
112→                  productCode,
113→                  campaingId,
114→                });
115→              } else {
116→                navigation.navigate('InvoiceCashbackOnboarding', {
117→                  conversionFactor,
118→                  productCode,
119→                  campaingId,
120→                });
121→              }
122→            }
123→          : handleOnPress(normalizedName);
124→
125→        return builder
126→          .reset()
127→          .setId(index + 1)
128→          .setText(product.name)
129→          .setIcon(icon)
130→          .setOnPress(onPress)
131→          .build();
132→      });
133→    },
134→    [
135→      handleOnPress,
136→      checkHasRedeemed,
137→      navigation,
